 64→public class TopologyMetadata {
 65→    private Logger log;
 66→
 67→    // the "__" (double underscore) string is not allowed for topology names, so it's safe to use to indicate
 68→    // that it's not a named topology
 69→    public static final String UNNAMED_TOPOLOGY = "__UNNAMED_TOPOLOGY__";
 70→    private static final Pattern EMPTY_ZERO_LENGTH_PATTERN = Pattern.compile("");
 71→
 72→    private final StreamsConfig config;
 73→    private final ProcessingMode processingMode;
 74→    private final TopologyVersion version;
 75→    private TopologyMetricsCache metricsCache;
 76→    private final TaskExecutionMetadata taskExecutionMetadata;
 77→    private final Set<String> pausedTopologies;
 78→
 79→    private final ConcurrentNavigableMap<String, InternalTopologyBuilder> builders; // Keep sorted by topology name for readability
 80→
 81→    private ProcessorTopology globalTopology;
 82→    private final Map<String, StateStore> globalStateStores = new HashMap<>();
 83→    private final Set<String> allInputTopics = new HashSet<>();
 84→    private final Map<String, Long> threadVersions = new ConcurrentHashMap<>();
 85→
 86→    public static class TopologyVersion {
 87→        public AtomicLong topologyVersion = new AtomicLong(0L); // the local topology version
 88→        public ReentrantLock topologyLock = new ReentrantLock();
 89→        public Condition topologyCV = topologyLock.newCondition();
 90→        public List<TopologyVersionListener> activeTopologyUpdateListeners = new LinkedList<>();
 91→    }
 92→
 93→    public static class TopologyVersionListener {
 94→        final long topologyVersion; // the (minimum) version to wait for these threads to cross
 95→        final KafkaFutureImpl<Void> future; // the future waiting on all threads to be updated
 96→
 97→        public TopologyVersionListener(final long topologyVersion, final KafkaFutureImpl<Void> future) {
 98→            this.topologyVersion = topologyVersion;
 99→            this.future = future;
100→        }
101→    }
102→
103→    public TopologyMetadata(final InternalTopologyBuilder builder,
104→                            final StreamsConfig config) {
105→        this.version = new TopologyVersion();
106→        this.processingMode = StreamsConfigUtils.processingMode(config);
107→        this.config = config;
108→        this.log = LoggerFactory.getLogger(getClass());
109→        this.pausedTopologies = ConcurrentHashMap.newKeySet();
110→
111→        builders = new ConcurrentSkipListMap<>();
112→        if (builder.hasNamedTopology()) {
113→            builders.put(builder.topologyName(), builder);
114→        } else {
115→            builders.put(UNNAMED_TOPOLOGY, builder);
116→        }
117→        this.taskExecutionMetadata = new TaskExecutionMetadata(builders.keySet(), pausedTopologies, processingMode);
118→    }
119→
120→    public TopologyMetadata(final ConcurrentNavigableMap<String, InternalTopologyBuilder> builders,
121→                            final StreamsConfig config) {
122→        this.version = new TopologyVersion();
123→        this.processingMode = StreamsConfigUtils.processingMode(config);
124→        this.config = config;
125→        this.log = LoggerFactory.getLogger(getClass());
126→        this.pausedTopologies = ConcurrentHashMap.newKeySet();
127→
128→        this.builders = builders;
129→        if (builders.isEmpty()) {
130→            log.info("Created an empty KafkaStreams app with no topology");
131→        }
132→        this.taskExecutionMetadata = new TaskExecutionMetadata(builders.keySet(), pausedTopologies, processingMode);
133→    }
134→
135→    // Need to (re)set the log here to pick up the `processId` part of the clientId in the prefix
136→    public void setLog(final LogContext logContext) {
137→        log = logContext.logger(getClass());
138→    }
139→    
140→    public ProcessingMode processingMode() {
141→        return processingMode;
142→    }
143→
144→    public long topologyVersion() {
145→        return version.topologyVersion.get();
146→    }
147→
148→    private void lock() {
149→        version.topologyLock.lock();
150→    }
151→
152→    private void unlock() {
153→        version.topologyLock.unlock();
154→    }
155→
156→    public Collection<String> sourceTopicsForTopology(final String name) {
157→        return builders.get(name).fullSourceTopicNames();
158→    }
159→
160→    public boolean needsUpdate(final String threadName) {
161→        return threadVersions.get(threadName) < topologyVersion();
162→    }
163→
164→    public void registerThread(final String threadName) {
165→        threadVersions.put(threadName, 0L);
166→    }
167→
168→    public void unregisterThread(final String threadName) {
169→        threadVersions.remove(threadName);
170→        maybeNotifyTopologyVersionListeners();
171→    }
172→
173→    public TaskExecutionMetadata taskExecutionMetadata() {
174→        return taskExecutionMetadata;
175→    }
176→
177→    public void executeTopologyUpdatesAndBumpThreadVersion(final Consumer<Set<String>> handleTopologyAdditions,
178→                                                           final Consumer<Set<String>> handleTopologyRemovals) {
179→        try {
180→            version.topologyLock.lock();
181→            final long latestTopologyVersion = topologyVersion();
182→            handleTopologyAdditions.accept(namedTopologiesView());
183→            handleTopologyRemovals.accept(namedTopologiesView());
184→            threadVersions.put(Thread.currentThread().getName(), latestTopologyVersion);
185→        } finally {
186→            version.topologyLock.unlock();
187→        }
188→    }
189→
190→    public void maybeNotifyTopologyVersionListeners() {
191→        try {
192→            lock();
193→            final long minThreadVersion = minimumThreadVersion();
194→            final Iterator<TopologyVersionListener> iterator = version.activeTopologyUpdateListeners.listIterator();
195→            TopologyVersionListener topologyVersionListener;
196→            while (iterator.hasNext()) {
197→                topologyVersionListener = iterator.next();
198→                final long topologyVersionWaitersVersion = topologyVersionListener.topologyVersion;
199→                if (minThreadVersion >= topologyVersionWaitersVersion) {
200→                    topologyVersionListener.future.complete(null);
201→                    iterator.remove();
202→                    log.info("All threads are now on topology version {}", topologyVersionListener.topologyVersion);
203→                }
204→            }
205→        } finally {
206→            unlock();
207→        }
208→    }
209→
210→    // Return the minimum version across all live threads, or Long.MAX_VALUE if there are no threads running
211→    private long minimumThreadVersion() {
212→        final Optional<Long> minVersion = threadVersions.values().stream().min(Long::compare);
213→        return minVersion.orElse(Long.MAX_VALUE);
214→    }
215→
216→    public void wakeupThreads() {
217→        try {
218→            lock();
219→            version.topologyCV.signalAll();
220→        } finally {
221→            unlock();
222→        }
223→    }
224→
225→    public void maybeWaitForNonEmptyTopology(final Supplier<StreamThread.State> threadState) {
226→        if (isEmpty() && threadState.get().isAlive()) {
227→            try {
228→                lock();
229→                while (isEmpty() && threadState.get().isAlive()) {
230→                    try {
231→                        log.debug("Detected that the topology is currently empty, waiting for something to process");
232→                        version.topologyCV.await();
233→                    } catch (final InterruptedException e) {
234→                        log.error("StreamThread was interrupted while waiting on empty topology", e);
235→                    }
236→                }
237→            } finally {
238→                unlock();
239→            }
240→        }
241→    }
242→
243→    /**
244→     * Adds the topology and registers a future that listens for all threads on the older version to see the update
245→     */
246→    public void registerAndBuildNewTopology(final KafkaFutureImpl<Void> future, final InternalTopologyBuilder newTopologyBuilder) {
247→        try {
248→            lock();
249→            buildAndVerifyTopology(newTopologyBuilder);
250→            log.info("New NamedTopology {} passed validation and will be added, old topology version is {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
251→            version.topologyVersion.incrementAndGet();
252→            version.activeTopologyUpdateListeners.add(new TopologyVersionListener(topologyVersion(), future));
253→            builders.put(newTopologyBuilder.topologyName(), newTopologyBuilder);
254→            wakeupThreads();
255→            log.info("Added NamedTopology {} and updated topology version to {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
256→        } catch (final Throwable throwable) {
257→            log.error("Failed to add NamedTopology {}, please retry the operation.", newTopologyBuilder.topologyName());
258→            future.completeExceptionally(throwable);
259→        } finally {
260→            unlock();
261→        }
262→    }
